local repo      = "https://raw.githubusercontent.com/deividcomsono/Obsidian/main/"
local moduleURL = "https://raw.githubusercontent.com/checkurasshole/INK/main/AgeOfTitansModule"

local Library      = loadstring(game:HttpGet(repo .. "Library.lua"))()
local ThemeManager = loadstring(game:HttpGet(repo .. "addons/ThemeManager.lua"))()
local SaveManager  = loadstring(game:HttpGet(repo .. "addons/SaveManager.lua"))()
local CW           = loadstring(game:HttpGet(moduleURL))()

local Options = Library.Options
local Toggles = Library.Toggles

local Window = Library:CreateWindow({
    Title            = "COMBOWICK",
    Icon             = 6031071057,
    NotifySide       = "Right",
    ShowCustomCursor = false,
    AutoShow         = true,
})

local Tabs = {
    Main            = Window:AddTab("Libreng Item",  "star"),
    ["Mga Setting ng UI"] = Window:AddTab("Mga Setting ng UI", "settings"),
}

local LeftGroup  = Tabs.Main:AddLeftGroupbox("Items")
local RightGroup = Tabs.Main:AddRightGroupbox("Player")

LeftGroup:AddDropdown("DevProductDrop", {
    Text    = "Pumili ng Item",
    Values  = CW.productNames,
    Default = CW.productNames[1],
    Callback = function(v)
        for _, p in ipairs(CW.products) do
            if p.name == v then CW.selectedProduct = p break end
        end
    end,
})

LeftGroup:AddButton({
    Text = "Kunin ang Napiling Item",
    Func = function() CW.fireProduct(Library, CW.selectedProduct) end,
})

LeftGroup:AddButton({
    Text = "Kunin Lahat ng Item",
    Func = function() CW.fireAll(Library) end,
})

LeftGroup:AddDivider()

getgenv().bbLoopSingle = false
LeftGroup:AddToggle("LoopSingle", {
    Text    = "Awtomatikong Kunin ang Napiling Item",
    Default = false,
    Callback = function(v)
        getgenv().bbLoopSingle = v
        while getgenv().bbLoopSingle and task.wait() do
            CW.fireProduct(Library, CW.selectedProduct)
        end
    end,
})

getgenv().bbLoopAll = false
LeftGroup:AddToggle("LoopAll", {
    Text    = "Awtomatikong Kunin Lahat ng Item",
    Default = false,
    Callback = function(v)
        getgenv().bbLoopAll = v
        while getgenv().bbLoopAll and task.wait() do
            CW.fireAll(Library)
        end
    end,
})

RightGroup:AddToggle("SpeedEnabled", {Text = "Pagpapabilis", Default = false})
RightGroup:AddSlider("WalkSpeedVal", {
    Text = "Bilis ng Paglakad", Default = 16, Min = 16, Max = 500, Rounding = 0,
})

RightGroup:AddDivider()

RightGroup:AddToggle("PlayerESP", {
    Text    = "ESP ng Manlalaro",
    Default = false,
    Callback = function(v)
        if v then CW.enableESP() else CW.removeESP() end
    end,
})

RightGroup:AddDivider()

RightGroup:AddDropdown("TeleportTarget", {
    Text    = "Pumili ng Manlalaro",
    Values  = CW.getPlayerNames(),
    Default = CW.getPlayerNames()[1],
})

RightGroup:AddButton({
    Text = "Mag-teleport sa Manlalaro",
    Func = function()
        local target = Options.TeleportTarget.Value
        if not target or target == "(no players)" then
            CW.notify(Library, "Error", "No player selected.") return
        end
        local tp     = game:GetService("Players"):FindFirstChild(target)
        local myHRP  = CW.LocalPlayer.Character and CW.LocalPlayer.Character:FindFirstChild("HumanoidRootPart")
        local tgtHRP = tp and tp.Character and tp.Character:FindFirstChild("HumanoidRootPart")
        if myHRP and tgtHRP then
            myHRP.CFrame = tgtHRP.CFrame + Vector3.new(0, 4, 0)
            CW.notify(Library, "Teleported", "You are now at " .. target)
        else
            CW.notify(Library, "Error", "Could not teleport to " .. target)
        end
    end,
})

RightGroup:AddButton({
    Text = "I-refresh ang Listahan ng mga Manlalaro",
    Func = function()
        Options.TeleportTarget:SetValues(CW.getPlayerNames())
        CW.notify(Library, "Refreshed", "Player list updated.")
    end,
})

CW.startHeartbeat(Toggles, Options)

local MenuGroup = Tabs["Mga Setting ng UI"]:AddLeftGroupbox("Menu", "wrench")
MenuGroup:AddToggle("ShowCustomCursor", {
    Text     = "Pasadyang Cursor",
    Default  = false,
    Callback = function(v) Library.ShowCustomCursor = v end,
})
MenuGroup:AddDivider()
MenuGroup:AddLabel("Keybind ng Menu"):AddKeyPicker("MenuKeybind", {Default="RightShift", NoUI=true, Text="Keybind ng Menu"})
MenuGroup:AddButton({Text="Unload", Func=function() Library:Unload() end})

Library.ToggleKeybind = Options.MenuKeybind
ThemeManager:SetLibrary(Library)
SaveManager:SetLibrary(Library)
SaveManager:IgnoreThemeSettings()
SaveManager:SetIgnoreIndexes({"MenuKeybind"})
ThemeManager:SetFolder("Combowick")
SaveManager:SetFolder("Combowick/settings")
SaveManager:BuildConfigSection(Tabs["Mga Setting ng UI"])
ThemeManager:ApplyToTab(Tabs["Mga Setting ng UI"])
SaveManager:LoadAutoloadConfig()

Library:OnUnload(function()
    CW.unloadAll(Library, Toggles)
end)

if _G.COMBOWICK_KEY then
    _G.COMBOWICK_FREE   = false
    _G.COMBOWICK_ACTIVE = nil
    _G.COMBOWICK_KEY    = false
end

if _G.COMBOWICK_FREE then
    _G.COMBOWICK_ACTIVE = true
    task.spawn(function()
        repeat task.wait(1) until _G.COMBOWICK_ACTIVE == false
        CW.showExpiredPopup(Library)
    end)
end